const payload = $json.report || $json.analysis || $json.data || $json;
const detections = Array.isArray(payload) ? payload : (payload.detections || []);
const alerts = Array.isArray(payload.created_alerts) ? payload.created_alerts : (payload.alerts || []);
const byKey = new Map();
for (const detection of detections) {
  const detectionAlerts = Array.isArray(detection.alerts) ? detection.alerts : [];
  const alertTypes = new Set(detectionAlerts.map((alert) => alert.alert_type || alert.type));
  const contract = detection.contract || {};
  const key = detection.key || `${detection.account_id || 'account'}:${detection.merchant_or_label || contract.provider || 'unknown'}:${detection.period || 'unknown'}`;
  byKey.set(key, {
    analysis_id: payload.analysis_id || payload.id,
    user_id: payload.user_id || $env.LIFEPILOT_USER_ID,
    key,
    merchant_or_label: detection.merchant_or_label || contract.provider || contract.name,
    period: detection.period,
    account_id: detection.account_id,
    category_id: detection.category_id,
    currency: detection.currency || 'EUR',
    average_amount: detection.average_amount,
    first_seen_at: detection.first_seen_at,
    last_seen_at: detection.last_seen_at,
    transaction_ids: detection.transaction_ids || [],
    contract,
    is_new_subscription: Boolean(contract.should_create) || alertTypes.has('new_recurring_debit') || alertTypes.has('subscription_without_contract'),
    has_price_variation: alertTypes.has('price_increase'),
    alerts: detectionAlerts
  });
}
for (const alert of alerts) {
  const key = alert.detection_key || alert.key;
  if (key && byKey.has(key)) byKey.get(key).alerts.push(alert);
}
return [...byKey.values()].map((item) => ({ json: item }));
